	('6193b407-8b1f-4743-bc33-88ca45a4ef67', 'Mega krasses Superbier', 'Neuzeit', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/brew-6193b407-8b1f-4743-bc33-88ca45a4ef67.png?t=1768859215067', '2026-01-19 19:49:45.690959+00', '35b36283-6593-4251-be06-da96f33b3a0d', 'Einfach unbeschreiblich ', 'beer', '{"fg": "3", "og": "12", "abv": "4.8", "ibu": "30", "hops": [], "color": "10", "malts": [], "yeast": [], "mash_ph": null, "boil_temp": null, "boil_time": null, "efficiency": null, "mash_steps": [], "attenuation": null, "primary_temp": null, "carbonation_g_l": "5.0", "batch_size_liters": "20", "mash_water_liters": null, "sparge_water_liters": null}', true, NULL, NULL, '03dd82d1-6352-45f5-9b15-3b8eb5dfd26c', 0, 'approved', NULL, '2026-01-22 11:04:50.373883+00', NULL, 'extract', NULL, NULL, 1, 27, 0.01601692937421854, 0, false, NULL, 2, 9, 4.80, 30, NULL),
	('a00a8893-55cd-4e18-bab5-7e932b7e79ba', 'Zesty Current', 'Blonde Ale', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-brew-a00a8893-55cd-4e18-bab5-7e932b7e79ba.png?t=1772987246687', '2026-03-08 16:22:44.511946+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Zesty Current ist ein strahlend goldenes Blonde Ale, das mit seinem lebendigen Aroma von spritzigen Zitrusfrüchten und exotischen Tropenfrüchten begeistert. Der Geschmack ist herrlich erfrischend, mit einer ausgewogenen, milden Bitterkeit und einem Hauch von süßlicher Malznote, die dem Bier Körper verleiht. Ein unglaublich süffiges Bier, das mit seiner leichten Textur und dem fruchtig-trockenen Abgang zum sofortigen Genuss einlädt.', 'beer', '{"fg": "3.2", "og": "11", "abv": "4.2", "ibu": "17.9", "hops": [{"name": "Citra", "time": "", "unit": "g", "alpha": "12.5", "usage": "First Wort", "amount": "2"}, {"name": "Citra", "time": "70", "unit": "g", "alpha": "12.5", "usage": "Boil", "amount": "13"}, {"name": "Citra", "time": "", "unit": "g", "alpha": "12.5", "usage": "Whirlpool", "amount": "29"}, {"name": "Simcoe", "time": "", "unit": "g", "alpha": "", "usage": "Dry Hop", "amount": "10"}, {"name": "Simcoe", "time": "", "unit": "g", "alpha": "", "usage": "Dry Hop", "amount": "20"}, {"name": "Simcoe", "time": "", "unit": "g", "alpha": "", "usage": "Dry Hop", "amount": "20"}], "color": "11.8", "malts": [{"name": "Pilsner Malz", "unit": "kg", "amount": "5", "color_ebc": ""}, {"name": "Münchner Malz", "unit": "kg", "amount": "0.5", "color_ebc": ""}, {"name": "Karamellmalz Hell", "unit": "kg", "amount": "0.35", "color_ebc": ""}], "yeast": [{"name": "Verdant IPA", "type": "dry", "unit": "g", "amount": "", "attenuation": "72"}], "mash_ph": null, "boil_temp": "100", "boil_time": "90", "efficiency": "62", "mash_steps": [], "attenuation": "72", "mash_method": "extract", "primary_temp": "21", "carbonation_g_l": "5", "batch_size_liters": "25", "fermentation_type": "top", "mash_water_liters": "17", "sparge_water_liters": "12"}', true, NULL, 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-cap-a00a8893-55cd-4e18-bab5-7e932b7e79ba.png?t=1772987278258', 'c7f0ceef-ad5a-422f-83b3-22c791bbe52e', 0, 'approved', NULL, '2026-03-08 16:22:44.511946+00', NULL, NULL, NULL, NULL, 1, 45, 0, 0, false, NULL, 0, 0, 4.20, NULL, '{"body": 0.5, "roast": 0.1, "source": "botlguide", "sweetness": 0.4, "bitterness": 0.7, "fruitiness": 0.9}'),
	('0169355e-9ac7-486c-85eb-f7ad5825bb96', 'Citra Glow', 'Pale Ale', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-brew-0169355e-9ac7-486c-85eb-f7ad5825bb96.png?t=1772654910660', '2026-03-04 20:06:15.712501+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Citra Glow ist ein erfrischendes Pale Ale, das mit intensiven Aromen von Grapefruit, Limette und tropischen Früchten begeistert. Sein leuchtendes Goldgelb und der schlanke Körper werden von einer ausgewogenen Bittere untermalt. Das trockene Finish und der geringe Alkoholgehalt machen es zu einem äußerst süffigen und belebenden Genuss.', 'beer', '{"fg": "3.0", "og": "10.2", "abv": "3.7", "ibu": "19.4", "hops": [{"name": "Citra", "time": "70", "unit": "g", "alpha": "13.5", "usage": "Boil", "amount": "3.1"}, {"name": "Citra", "time": "20", "unit": "g", "alpha": "13.5", "usage": "Boil", "amount": "6.2"}, {"name": "Citra", "time": "10", "unit": "g", "alpha": "13.5", "usage": "Boil", "amount": "6.2"}, {"name": "Citra", "time": "5", "unit": "g", "alpha": "13.5", "usage": "Boil", "amount": "6.2"}, {"name": "Citra", "time": "0", "unit": "g", "alpha": "13.5", "usage": "Dry Hop", "amount": "9.2"}], "color": "9.9", "malts": [{"name": "Pilsner Malz", "unit": "kg", "amount": "2.007", "color_ebc": ""}, {"name": "Pale Ale Malz", "unit": "kg", "amount": "2.007", "color_ebc": ""}, {"name": "Münchner Malz", "unit": "kg", "amount": "0.547", "color_ebc": ""}], "yeast": [{"name": "Germentis Safale US-05", "type": "dry", "unit": "g", "amount": "", "attenuation": "71,1"}], "mash_ph": null, "boil_temp": "100", "boil_time": "90", "efficiency": "58.4", "mash_steps": [{"name": "Einmaischen", "duration": "", "step_type": "strike", "temperature": "66"}, {"name": "1. Rast", "duration": "60", "temperature": "67"}, {"name": "2. Rast", "duration": "10", "temperature": "78"}, {"name": "Abmaischen", "duration": "", "step_type": "mashout", "temperature": "78"}], "attenuation": "71.1", "mash_method": "all_grain", "mash_proces