	('769cf2b1-ef9d-4b86-b30f-e24fb1df2dc4', 'Tradition''s Echo', 'Pils', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/brew-769cf2b1-ef9d-4b86-b30f-e24fb1df2dc4.png?t=1769516038501', '2026-01-17 11:12:19.700749+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Tradition''s Echo ist ein Pils, das mit seiner hellgoldenen Farbe und der feinen Schaumkrone ins Auge fällt. Zarte Aromen von edlem Hopfen verbinden sich mit einer subtilen Malzsüße. Am Gaumen entfaltet sich ein schlanker Körper mit einer angenehmen Bittere und einem erfrischenden, trockenen Abgang.', 'beer', '{"fg": "3.1", "og": "12", "abv": "4.8", "ibu": "30.5", "hops": [{"name": "Hallertauer Tradition", "time": "90", "unit": "g", "alpha": "7,2", "usage": "Boil", "amount": "32"}], "color": "8", "malts": [{"name": "Pilsner Malz", "unit": "kg", "amount": "3,7", "color_ebc": "5"}, {"name": "Weizen Malz", "unit": "kg", "amount": "0,65", "color_ebc": "4"}], "yeast": [{"name": "Obergärige Hefe", "type": "dry", "unit": "g", "amount": "7", "attenuation": "75"}], "mash_ph": null, "boil_temp": "100", "boil_time": "90", "efficiency": null, "mash_steps": [{"name": "Einmaischen", "duration": "", "step_type": "strike", "temperature": "50"}, {"name": "1. Rast", "duration": "20", "temperature": "52"}, {"name": "2. Rast", "duration": "40", "temperature": "63"}, {"name": "3. Rast", "duration": "30", "temperature": "72"}, {"name": "Abmaischen", "duration": "", "step_type": "mashout", "temperature": "78"}], "attenuation": "75", "mash_method": "all_grain", "mash_process": "step_mash", "primary_temp": "25", "carbonation_g_l": "5", "batch_size_liters": "20.8", "mash_water_liters": "16", "sparge_water_liters": "12"}', true, NULL, 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/caps/cap-769cf2b1-ef9d-4b86-b30f-e24fb1df2dc4.png?t=1768648634201', 'c7f0ceef-ad5a-422f-83b3-22c791bbe52e', 0, 'approved', NULL, NULL, NULL, 'all_grain', 'step_mash', 'bottom', 5, 45, 0, 0, false, NULL, 0, 5, 4.80, NULL, NULL),
	('3d8fe763-5439-4901-8df6-52d2b5647c72', 'Moonbeam Nectar', 'IPA', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/brew-3d8fe763-5439-4901-8df6-52d2b5647c72.png?t=1772572455810', '2026-03-03 21:05:33.828037+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Moonbeam Nectar, ein strahlend goldenes IPA, verführt die Sinne mit einem intensiven Bouquet von tropischen Früchten und lebhaften Zitrusnoten, dominiert vom Citra-Hopfen. Am Gaumen entfaltet sich ein saftiges Geschmacksprofil von Grapefruit und Mango, harmonisch eingebettet in eine angenehme, gut integrierte Bittere. Der trockene, erfrischende Abgang sorgt für ein unvergleichlich geschmeidiges Trinkerlebnis.', 'beer', '{"fg": "4.0", "og": "15.1", "abv": "6.1", "ibu": "46.6", "hops": [{"name": "Citra", "time": "75", "unit": "g", "alpha": "13.4", "usage": "First Wort", "amount": "15"}, {"name": "Citra", "time": "35", "unit": "g", "alpha": "13.4", "usage": "Boil", "amount": "10"}, {"name": "Citra", "time": "10", "unit": "g", "alpha": "13.4", "usage": "Boil", "amount": "10"}, {"name": "Citra", "time": "5", "unit": "g", "alpha": "13.4", "usage": "Boil", "amount": "15"}, {"name": "Citra", "time": "0", "unit": "g", "alpha": "13.4", "usage": "Dry Hop", "amount": "20"}, {"name": "", "time": "", "unit": "g", "alpha": "", "usage": "Dry Hop", "amount": "100"}], "color": "8", "malts": [{"name": "Wiener Malz", "unit": "kg", "amount": "3.3", "color_ebc": "3"}, {"name": "Pale Ale Malz", "unit": "kg", "amount": "2", "color_ebc": "5"}, {"name": "Caramünch II Malz", "unit": "kg", "amount": "0.15", "color_ebc": "2"}], "yeast": [{"name": "US-05", "type": "dry", "unit": "g", "amount": "11.5", "attenuation": "75"}], "mash_ph": null, "boil_temp": "100", "boil_time": "75", "efficiency": null, "mash_steps": [{"name": "Einmaischen", "duration": "", "step_type": "strike", "temperature": "50"}, {"name": "1. Rast", "duration": "60", "temperature": "66"}, {"name": "Abmaischen", "duration": "", "step_type": "mashout", "te