	('c9f80d56-2faa-42e0-b8ce-bf7a507412ff', 'Czech Zephyr', 'Böhmisches Pilsner', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-brew-c9f80d56-2faa-42e0-b8ce-bf7a507412ff.png?t=1772656209587', '2026-03-04 20:27:20.781825+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Czech Zephyr ist ein brillantes Böhmisches Pilsner, das mit seiner klaren, goldgelben Farbe und einer feinen, langanhaltenden Schaumkrone begeistert. Das betörende Aroma edler Saazer-Hopfen, gepaart mit einer subtilen Malznote, leitet ein erfrischendes Geschmackserlebnis ein. Am Gaumen präsentiert es sich wunderbar leicht und knackig, mit einer ausgewogenen Bitterkeit, die in einem herrlich trockenen und sauberen Abgang mündet.', 'beer', '{"fg": "4.7", "og": "17.9", "abv": "7.2", "ibu": "38.3", "hops": [{"name": "Saazer", "time": "90", "unit": "g", "alpha": "4", "usage": "First Wort", "amount": "10"}, {"name": "Magnum", "time": "90", "unit": "g", "alpha": "15", "usage": "Boil", "amount": "15"}, {"name": "Saazer", "time": "5", "unit": "g", "alpha": "4", "usage": "Boil", "amount": "50"}], "color": "8", "malts": [{"name": "Pilsner Malz", "unit": "kg", "amount": "5.5", "color_ebc": "3.2"}], "yeast": [{"name": "Fermentis Saflager W34/70", "type": "dry", "unit": "g", "amount": "", "attenuation": "75"}], "mash_ph": null, "boil_temp": "100", "boil_time": "90", "efficiency": "75", "mash_steps": [{"name": "Einmaischen", "duration": "", "step_type": "strike", "temperature": "57"}, {"name": "1. Rast", "duration": "30", "temperature": "64"}, {"name": "2. Rast", "duration": "30", "temperature": "72"}, {"name": "3. Rast", "duration": "10", "temperature": "77"}, {"name": "Abmaischen", "duration": "", "step_type": "mashout", "temperature": "77"}], "attenuation": "75", "mash_method": "all_grain", "mash_process": "step_mash", "primary_temp": "12", "carbonation_g_l": "5.6", "batch_size_liters": "17.3", "fermentation_type": "bottom", "mash_water_liters": "11", "sparge_water_liters": "18"}', true, NULL, 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-cap-c9f80d56-2faa-42e0-b8ce-bf7a507412ff.png?t=1772656245561', 'c7f0ceef-ad5a-422f-83b3-22c791bbe52e', 0, 'approved', NULL, '2026-03-04 20:27:20.781825+00', NULL, NULL, 'step_mash', NULL, 5, 45, 0, 0, false, NULL, 0, 0, 7.20, NULL, '{"body": 0.4, "roast": 0, "source": "botlguide", "sweetness": 0.3, "bitterness": 0.75, "fruitiness": 0.1}'),
	('4f90ea0e-0138-4d4b-bf09-50b2338be474', 'Blanc Surrender', 'Saison', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/brew-4f90ea0e-0138-4d4b-bf09-50b2338be474.png?t=1769174815034', '2026-01-23 13:24:01.151442+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Blanc Surrender ist ein komplexes Saison, das mit seiner hellen, leicht trüben Farbe und dem feinen Schaum verzaubert. Aromen von Stachelbeere und weißen Trauben, dank der Hallertau Blanc Hopfung, verbinden sich mit würzigen Noten von Roggen und der subtilen Süße von Weizenmalz. Der hohe Vergärungsgrad sorgt für einen trockenen, erfrischenden Abgang und ein leichtfüßiges Mundgefühl.', 'beer', '{"fg": "0.9", "og": "14.8", "abv": "7.5", "ibu": "33.7", "hops": [{"name": "Hallertau Blanc", "time": "60", "unit": "g", "alpha": "8.2", "usage": "Boil", "amount": 20}, {"name": "Hallertau Blanc", "time": "10", "unit": "g", "alpha": "8.2", "usage": "Boil", "amount": 20}, {"name": "Hallertau Blanc", "time": "5", "unit": "g", "alpha": "8.2", "usage": "Boil", "amount": 20}, {"name": "Hallertau Blanc", "time": "0", "unit": "g", "alpha": "8.2", "usage": "Whirlpool", "amount": 40}, {"name": "Hallertau Blanc", "time": "0", "unit": "g", "alpha": "8.2", "usage": "Dry Hop", "amount": 40}], "color": "18.6", "malts": [{"name": "Pilsener Malz", "unit": "kg", "amount": 2.92, "color_ebc": "8"}, {"name": "Weizenmalz", "unit": "kg", "amount": 0.94, "color_ebc": "10"}, {"name": "Roggenmalz", "unit": "kg", "amount": 0.55, "color_ebc": "12"}, {"name": "Spitzmalz", "unit": "kg", "amount": 0.55, "color_ebc": "22"}, {"name": "Wiener Malz", "unit": "kg", "amount": 0.55, "color_ebc": "18"}], "steps": [{"title": "Läutern", "instruction": "Vorderwürze abziehen und Nachguss geben."}, {"title": "Kochen", "instruction": "Würze 60 Minuten kochen. Hopfengaben laut Plan."}, {"title": "Gärung", "instruction": "Gärtemperatur: 17°C."}], "yeast": [{"name": "WHC Farmhouse Vibes", "attenuation": "94"}], "boil_temp": 100, "boil_time": 60, "color_ebc": 20, "efficiency": "63", "mash_steps": [{"name": "Einmaischen", "duration": "", "step_type": "strike", "temperature": "76"}, {"name": "1. Rast", "duration": "30", "temperature": "67"}, {"name": "Abmaischen", "duration": "", "step_type": "mashout", "temperature": "78"}], "attenuation": "94", "mash_method": "all_grain", "mash_process": "step_mash", "carbonation_g_l": 6, "batch_size_liters": "17.6", "mash_water_liters": "16", "sparge_water_liters": "10"}', true, NULL, '🍺', 'c7f0ceef-ad5a-422f-83b3-22c791bbe52e', 1, 'approved', NULL, NULL, NULL, 'all_grain', 'step_mash', 'top', 3, 59, 0.011940959356506069, 0, false, NULL, 1, 4, 7.50, NULL, NULL),
	('91d303d3-4985-4d90-8b8b-45cd57312787', 'Apex Current', 'India Pale Ale', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-brew-91d303d3-4985-4d90-8b8b-45cd57312787.png?t=1772657136482', '2026-03-04 20:45:13.542217+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Apex Current ist ein leichtfüßiges India Pale Ale, das mit seiner strahlend goldenen Farbe und einer dezenten Trübung begeistert. Intensive Aromen von Grapefruit, Passionsfrucht und einem Hauch Pinie aus Simcoe- und Cascade-Hopfen prägen das Profil. Am Gaumen bietet es einen schlanken Körper, eine knackige, harmonische Bittere und ein erfrischend trockenes Finish, das zum unbeschwerten Genuss bei nur 3.5% ABV einlädt.', 'beer', '{"fg": "2.1", "og": "11.3", "abv": "4.9", "ibu": "51.7", "hops": [{"name": "Simcoe", "time": "90", "unit": "g", "alpha": "12.9", "usage": "Boil", "amount": "35"}, {"name": "Simcoe", "time": "45", "unit": "g", "alpha": "12.9", "usage": "Boil", "amount": "35"}, {"name": "Simcoe", "time": "5", "unit": "g", "alpha": "12.9", "usage": "Boil", "amount": "35"}, {"name": "Simcoe", "time": "", "unit": "g", "alpha": "", "usage": "Dry Hop", "amount": "115"}, {"name": "Cascade", "time": "", "unit": "g", "alpha": "", "usage": "Dry Hop", "amount": "65"}], "color": "8.8", "malts": [{"name": "Pilsner Malz", "unit": "kg", "amount": "6.5", "color_ebc": ""}, {"name": "Cara hell", "unit": "kg", "amount": "0.5", "color_ebc": ""}, {"name": "Cara Red", "unit": "kg", "amount": "0.5", "color_ebc": ""}, {"name": "Haferflocken", "unit": "kg", "amount": "0.5", "color_ebc": ""}], "yeast": [{"name": "Fermentis Safale US-05", "type": "dry", "unit": "g", "amount": "", "attenuation": "81.8"}], "mash_ph": null, "boil_temp": "100", "boil_time": "90", "efficiency": "95", "mash_steps": [{"name": "Einmaischen", "duration": "", "step_type": "strike", "temperature": "57"}, {"name": "1. Rast", "duration": "10", "temperature": "57"}, {"name": "2. Rast", "duration": "60", "temperature": "65"}, {"name": "3. Rast", "duration": "20", "temperature": "72"}, {"name": "4. Rast", "duration": "5", "temperature": "78"}, {"name": "Abmaischen", "duration": "", "step_type": "mashout", "temperature": "78"}], "attenuation": "81.8", "mash_method": "all_grain", "mash_process": "step_mash", "primary_temp": "20", "carbonation_g_l": "4", "batch_size_liters": "50.5", "fermentation_type": "top", "mash_water_liters": "50", "sparge_water_liters": "16"}', true, NULL, 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-cap-91d303d3-4985-4d90-8b8b-45cd57312787.png?t=1772657169823', 'c7f0ceef-ad5a-422f-83b3-22c791bbe52e', 0, 'approved', NULL, '2026-03-04 20:45:13.542217+00', NULL, NULL, 'step_mash', NULL, 6, 59, 0.134419964784454, 0, false, NULL, 1, 1, 4.90, NULL, '{"body": 0.5, "roast": 0.1, "source": "botlguide", "sweetness": 0.4, "bitterness": 0.7, "fruitiness": 0.7}'),
	('9eb040af-462a-4282-bb00-a97c37f83443', 'Rhine Maiden Blonde', 'Kölsch', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/brew-9eb040af-462a-4282-bb00-a97c37f83443.png?t=1769180174468', '2026-01-23 14:53:52.714168+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Rhine Maiden Blonde ist ein erfrischendes Kölsch mit feinen Aromen von Honig und Getreide, unterlegt von einer dezenten floralen Hopfennote. Die helle, goldene Farbe und der leicht prickelnde Körper machen dieses Bier besonders süffig. Ein sanftes Mundgefühl führt zu einem sauberen, knackigen Abgang.', 'beer', '{"fg": "4.1", "og": "14.5", "abv": "5.5", "ibu": "30.8", "hops": [{"name": "Tettnanger", "time": "90", "unit": "g", "alpha": "3.1", "usage": "First Wort", "amount": 30}, {"name": "Tettnanger", "time": "70", "unit": "g", "alpha": "3.1", "usage": "Boil", "amount": 54}, {"name": "Tettnanger", "time": "10", "unit": "g", "alpha": "3.1", "usage": "Boil", "amount": 9}], "color": "6.8", "malts": [{"name": "Pilsener Malz (Weyermann Bio)", "unit": "kg", "amount": 4.8, "color_ebc": "3"}, {"name": "Weizenmalz hell (Weyermann Bio)", "unit": "kg", "amount": 0.55, "color_ebc": "4"}, {"name": "Sauermalz", "unit": "kg", "amount": 0.12, "color_ebc": "4"}], "steps": [{"title": "Läutern", "instruction": "Vorderwürze abziehen und Nachguss geben."}, {"title": "Kochen", "instruction": "Würze 90 Minuten kochen. Tettnanger Gaben beachten (30g VHW, 54g @ 70min, 9g @ 10min)."}, {"title": "Gärung", "instruction": "Gärtemperatur: 13°C. Hauptgärung ca. 9 Tage."}, {"title": "Reifung", "instruction": "8 Wochen bei ca. 1°C lagern."}], "yeast": [{"name": "Wyeast #2565 Kölsch", "attenuation": "73"}], "mash_ph": null, "boil_temp": 100, "boil_time": 90, "color_ebc": 9, "mash_steps": [{"name": "Einmaischen", "duration": "", "step_type": "strike", "temperature": "55"}, {"name": "Eiweißrast", "duration": "10", "temperature": "55"}, {"name": "Maltoserast", "duration": "40", "temperature": "63"}, {"name": "Verzuckerung", "duration": "15", "temperature": "72"}, {"name": "Abmaischen", "duration": "", "step_type": "mashout", "temperature": "78"}], "attenuation": "73", "mash_method": "all_grain", "mash_process": "step_mash", "primary_temp": 13, "carbonation_g_l": 5.5, "batch_size_liters": "21.5", "mash_water_liters": 25, "sparge_water_liters": "6.0"}', true, NULL, 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/caps/cap-9eb040af-462a-4282-bb00-a97c37f83443.png?t=1770030473774', 'c7f0ceef-ad5a-422f-83b3-22c791bbe52e', 3, 'approved', NULL, NULL, NULL, 'all_grain', 'step_mash', 'top', 5, 59, 0.01794625498964061, 0, false, NULL, 1, 13, 5.50, NULL, NULL),
	('90296263-a198-4aac-a8d8-e3d5daabd66b', 'Pristine Core', 'Maibock', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-brew-90296263-a198-4aac-a8d8-e3d5daabd66b.png?t=1772661906257', '2026-03-04 21:59:03.576605+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Dieses Bier strahlt in einem klaren, hellgoldenen Glanz und verströmt dezente Aromen von frischem Getreide und einem Hauch feiner Malzsüße. Am Gaumen überzeugt es mit einem krispen und sauberen Geschmack, bei dem eine ausgewogene, nicht aufdringliche Bitterkeit auf eine milde Brotnote trifft. Der leichte Körper und der trockene Abgang sorgen für ein erfrischendes und sehr zugängliches Trinkerlebnis.', 'beer', '{"fg": "3.0", "og": "11.5", "abv": "4.5", "ibu": "28.5", "hops": [{"form": "Pellet", "name": "Magnum", "time": "70", "unit": "g", "alpha": "14", "usage": "Boil", "amount": "15"}], "color": "5.6", "malts": [{"name": "Pilsner Malz", "unit": "kg", "amount": "4"}], "notes": "Beispiel...", "yeast": [{"name": "US-05", "type": "dry", "unit": "g", "amount": "", "attenuation": "75"}], "yeasts": [{"name": "Danstar Nottingham Ale", "unit": "pkg", "amount": "1"}], "trub_loss": null, "mash_steps": [{"name": "Rast 1", "duration": "45", "temperature": "63"}], "attenuation": "75", "mash_method": "all_grain", "mash_process": "infusion", "primary_temp": "19.0", "boil_off_rate": null, "grain_absorption": null, "batch_size_liters": "20.0", "boil_time_minutes": "90", "cooling_shrinkage": null, "fermentation_type": "top", "mash_water_liters": "14", "sparge_water_liters": "14.7"}', true, NULL, 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-cap-90296263-a198-4aac-a8d8-e3d5daabd66b.png?t=1772662082162', 'c7f0ceef-ad5a-422f-83b3-22c791bbe52e', 0, 'approved', NULL, '2026-03-04 21:59:03.576605+00', NULL, NULL, 'infusion', NULL, 1, 45, 0, 0, false, NULL, 0, 1, 4.50, NULL, '{"body": 0.4, "roast": 0.1, "source": "botlguide", "sweetness": 0.4, "bitterness": 0.7, "fruitiness": 0.1}'),
	('d7160083-1961-413f-add3-749c624af546', 'Noble Perle', 'Pilsner', 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-brew-d7160083-1961-413f-add3-749c624af546.png?t=1772655495479', '2026-03-04 20:17:42.266636+00', '6ac6b581-9ee6-45f4-9cb3-2fc8c3f4a9cc', 'Unser Noble Perle besticht durch sein brillantes Gold und eine feine, stabile Schaumkrone. Die Nase wird umschmeichelt von frischen Getreidenoten, unterlegt mit subtilen blumig-würzigen Akzenten der Perle- und Hallertauer Mittelfrüh-Hopfen. Am Gaumen entfaltet sich ein knackig-erfrischender Geschmack, der eine harmonische Balance zwischen zarter Malzsüße und einer edlen, ausgewogenen Bittere bietet. Mit seinem schlanken Körper und dem trockenen, klaren Abgang ist es ein äußerst süffiges und erfrischendes Pilsner.', 'beer', '{"fg": "2.3", "og": "9.2", "abv": "3.6", "ibu": "38.1", "hops": [{"name": "Perle", "time": "75", "unit": "g", "alpha": "10", "usage": "Boil", "amount": "50"}, {"name": "Perle", "time": "40", "unit": "g", "alpha": "10", "usage": "Boil", "amount": "30"}, {"name": "Hallertauer Mittelfrüh", "time": "5", "unit": "g", "alpha": "3.7", "usage": "Boil", "amount": "20"}], "color": "7.3", "malts": [{"name": "Pilsner Malz", "unit": "kg", "amount": "9.5", "color_ebc": ""}, {"name": "Cara hell", "unit": "kg", "amount": "1", "color_ebc": ""}], "yeast": [{"name": "Saflager W34/70", "type": "dry", "unit": "g", "amount": "", "attenuation": "75"}], "mash_ph": null, "boil_temp": "100", "boil_time": "75", "efficiency": "69", "mash_steps": [{"name": "Einmaischen", "duration": "", "step_type": "strike", "temperature": "66"}, {"name": "1. Rast", "duration": "25", "temperature": "62"}, {"name": "2. Rast", "duration": "30", "temperature": "72"}, {"name": "Abmaischen", "duration": "", "step_type": "mashout", "temperature": "78"}], "attenuation": "75", "mash_method": "all_grain", "mash_process": "step_mash", "primary_temp": "12", "carbonation_g_l": null, "batch_size_liters": "60.0", "fermentation_type": "bottom", "mash_water_liters": "50", "sparge_water_liters": "28"}', true, NULL, 'https://ciwatubrwvzpglifetod.supabase.co/storage/v1/object/public/labels/ai-cap-d7160083-1961-413f-add3-749c624af546.png?t=1772655534158', 'c7f0ceef-ad5a-422f-83b3-22c791bbe52e', 1, 'approved', NULL, '2026-03-04 20:17:42.266636+00', NULL, NULL, 'step_mash', NULL, 4, 50, 0.04464509730566177, 0, false, NULL, 0, 3, 3.60, NULL, '{"body": 0.3, "roast": 0, "source": "botlguide", "sweetness": 0.2, "bitterness": 0.8, "fruitiness": 0.1}');
